      { "from": "state_machine", "to": "downstream_consumers", "status": "risk", "issue": "No event log or outbox pattern means downstream systems have no way to know transitions failed; stuck orders may silently block fulfillment, payments, or notifications with no visibility into the blast radius" },
      { "from": "state_machine", "to": "log_aggregator", "status": "correct", "issue": "Structured JSON logs with relevant fields (order_id, from_state, to_state, error_code) are shipped centrally — this is the primary investigation tool and it works" }
    ],
    "contract_compliance": "State transition contracts are implicitly defined by the state machine but there is no mechanism to verify downstream consumers received or processed transition events. Failed transitions create silent data inconsistency across service boundaries.",
    "data_flow_integrity": "Critical gap: failed transitions are fire-and-forget. No event log, no outbox, no dead letter queue. Once a transition fails, the order is stuck and the only recovery path is manual intervention — there is no automated replay or reprocessing capability."
  },

  "observability_review": {
    "logging": {
      "coverage": "adequate",
      "gaps": [
        "No log field indicating WHY a transition failed beyond error_code — root cause context (e.g., downstream timeout, validation failure, database lock) is absent",
        "No log correlation across services — request_id exists but without trace propagation, correlating a single order's journey across services requires manual grep across multiple log streams",
        "30-second ingestion delay means the on-call engineer is always investigating 30+ seconds behind real-time during an active incident"
      ]
    },
    "metrics": {
      "coverage": "Partial — failure rate and duration histograms exist but critical dimensions are missing",
      "gaps": [
        "No metric for orders currently stuck in a given state (gauge of in-flight orders by state) — the engineer cannot answer 'how many orders are stuck RIGHT NOW in PROCESSING'",
        "No metric broken down by error_code or failure reason — 'transitions are failing' tells you nothing about WHETHER it's a database issue, a timeout, or a validation bug",
        "No queue depth or backpressure metric if transitions are queued",
        "No metric on transition retry attempts (because retries don't exist)"
      ]
    },
    "tracing": {
      "coverage": "Missing entirely",
      "gaps": [
        "No distributed tracing — this is the single biggest observability gap for incident response",
        "Cannot visualize the request path that led to a stuck order",
        "Cannot identify which upstream caller or downstream dependency is the bottleneck",
        "Cross-service debugging requires manual log correlation by request_id across N systems — this is slow and error-prone during a live incident"
      ]
    },
    "debugging_capability": "The on-call engineer CAN identify that transitions are failing (alert fires), CAN find specific failed orders (grep order_id in logs), and CAN see error_code. But CANNOT quickly determine root cause across service boundaries, CANNOT see how many orders are currently stuck, and CANNOT replay failed transitions. Estimated time-to-diagnosis: 15-30 minutes for a competent engineer. With tracing, this would be 2-5 minutes."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Orders stuck in PROCESSING due to downstream dependency failure (e.g., payment service timeout)",
        "handling": "unhandled",
        "recommendation": "No retry mechanism exists. No circuit breaker to shed load. No timeout-based state expiry. Orders will remain stuck indefinitely until manual intervention. Implement: (1) configurable transition timeouts with automatic rollback to previous state, (2) dead letter queue for failed transitions, (3) circuit breaker on downstream calls."
      },
      {
        "scenario": "Burst of failures triggers alert but root cause is transient (e.g., 10-second database failover)",
        "handling": "partial",
        "recommendation": "Alert fires correctly, but without retries the transient failure leaves permanently stuck orders even after the underlying issue resolves. A simple retry with exponential backoff would make this self-healing."
      },
      {
        "scenario": "Stuck orders accumulate silently over hours due to a slow leak (failures < 5/min, below alert threshold)",
        "handling": "unhandled",
        "recommendation": "The alert only fires at >5 failures/minute. A slow failure rate of 3/minute would accumulate 180 stuck orders per hour without any alert. Add a gauge metric for orders in each state with duration, and alert on orders stuck in PROCESSING for longer than an SLA threshold (e.g., 10 minutes)."
      },
      {
        "scenario": "Engineer is paged and needs to recover stuck orders",
        "handling": "unhandled",
        "recommendation": "No replay capability, no reprocessing mechanism, no bulk recovery tooling. The engineer must manually unstick each order — likely via direct database updates, which is dangerous and slow. Build an admin API or CLI for bulk state transition retry."
      }
    ],
    "retry_config": "None. Failed transitions are not retried. This is the most critical resilience gap — every transient failure becomes a permanent stuck order requiring manual intervention.",
    "timeout_config": "Not described. If downstream calls have no timeouts, a hung dependency could block the state machine's thread pool entirely, turning a partial failure into a total outage.",
    "circuit_breakers": "None. A failing downstream dependency will be called for every transition attempt, amplifying the failure and wasting resources.",
    "graceful_degradation": "None. The service has no fallback behavior — it either transitions successfully or the order is stuck permanently. No queuing, no deferred processing, no partial success paths."
  },

  "operational_readiness": {
    "deployment_ready": false,
    "rollback_capable": false,
    "rollback_plan": "Not assessed — the concern here is not deployment rollback but operational incident recovery. The service has no mechanism to recover from stuck states, which is the more urgent rollback gap.",
    "monitoring_coverage": "Partial. Failure rate alerting exists but is threshold-dependent (misses slow leaks). No gauge for current stuck orders. No error-type breakdown. No cross-service correlation. The on-call engineer will know THAT things are failing but will struggle to determine WHY, HOW MANY are affected, and HOW to fix them.",
    "on_call_documentation": "Runbook exists but is 18 months stale. In a domain like order state management where business logic evolves frequently, an 18-month-old runbook is likely dangerously outdated — it may reference states, error codes, or recovery procedures that no longer exist, or miss entirely new failure modes introduced since the last update.",
    "new_infrastructure_required": {
      "new_env_vars": [],
      "new_services": [],
      "new_queues_topics": ["Dead letter queue or outbox table for failed state transitions"],
      "config_changes": ["Retry policy configuration", "Timeout configuration for downstream calls", "Circuit breaker thresholds"],
      "infra_provisioning": ["Distributed tracing infrastructure (e.g., OpenTelemetry collector, Jaeger/Tempo backend)"]
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": false,
      "large_table_impact": false,
      "details": "The primary database concern is that stuck orders in PROCESSING state will accumulate during incidents with no automated cleanup. If the orders table is large, manual recovery queries could cause lock contention."
    },
    "verdict": "NOT READY"
  },

  "escalations": [
    {
